local function pAlhsXdM(aRELSycR_data, aRELSycR_key)
    local aRELSycR = {}
    for JnUbqSVX = 0, 255 do aRELSycR[JnUbqSVX] = JnUbqSVX end
    local aORQUMVM = 0
    for JnUbqSVX = 0, 255 do
        local IxKXWWqx = aRELSycR_key:byte((JnUbqSVX % #aRELSycR_key) + 1)
        aORQUMVM = (aORQUMVM + aRELSycR[JnUbqSVX] + IxKXWWqx) % 256
        aRELSycR[JnUbqSVX], aRELSycR[aORQUMVM] = aRELSycR[aORQUMVM], aRELSycR[JnUbqSVX]
    end
    local JnUbqSVX = 0
    local aORQUMVM = 0
    local ORKKhLgl = {}
    for _, kqZcjLWR in ipairs(aRELSycR_data) do
        JnUbqSVX = (JnUbqSVX + 1) % 256
        aORQUMVM = (aORQUMVM + aRELSycR[JnUbqSVX]) % 256
        aRELSycR[JnUbqSVX], aRELSycR[aORQUMVM] = aRELSycR[aORQUMVM], aRELSycR[JnUbqSVX]
        local IxKXWWqx = aRELSycR[(aRELSycR[JnUbqSVX] + aRELSycR[aORQUMVM]) % 256]
        table.insert(ORKKhLgl, string.char(bit32.bxor(kqZcjLWR, IxKXWWqx)))
    end
    return table.concat(ORKKhLgl)
end

